//! `lattice_vq` — PyO3 wheel exposing the sovereign Rust E8/Leech lattice
//! quantizer (crate `distributed-inference`) to PyTorch/NumPy.
//!
//! The lattice math is NOT reimplemented here. Every value is produced by the
//! sovereign decoders:
//!   * `distributed_inference::leech_quantizer::nearest_leech`  (LEECH_DIM = 24)
//!   * `distributed_inference::leech_quantizer::leech_quantization_error_sq`
//!   * `distributed_inference::e8_quantizer::nearest_e8`        (E8_DIM = 8)
//!   * `distributed_inference::e8_quantizer::quantization_error_sq`
//!
//! This crate is a thin batched + GIL-releasing + rayon-parallel wrapper.
//!
//! Contract (agreed with the trainer subagent):
//!   nearest_leech_batch(x: ndarray[B,24] f64) -> ndarray[B,24] i64
//!   nearest_e8_batch(x: ndarray[B,8]  f64) -> ndarray[B,8]  i64
//!   quant_error_batch_leech(x: ndarray[B,24] f64) -> ndarray[B] f64
//!   quant_error_batch_e8(x: ndarray[B,8]  f64) -> ndarray[B] f64

use numpy::ndarray::{Array1, Array2};
use numpy::{IntoPyArray, PyArray1, PyArray2, PyReadonlyArray2, PyUntypedArrayMethods};
use pyo3::exceptions::PyValueError;
use pyo3::prelude::*;
use rayon::prelude::*;

use distributed_inference::e8_quantizer::{nearest_e8, quantization_error_sq as e8_error_sq};
use distributed_inference::leech_quantizer::{
    leech_quantization_error_sq, nearest_leech, LEECH_DIM,
};

const E8_DIM: usize = 8;

/// Copy one row of a row-major `[B, D]` slice into a fixed-size array.
#[inline]
fn row_to_array<const D: usize>(flat: &[f64], row: usize) -> [f64; D] {
    let mut out = [0.0f64; D];
    let base = row * D;
    out.copy_from_slice(&flat[base..base + D]);
    out
}

/// nearest_leech_batch(x: ndarray[B,24] f64) -> ndarray[B,24] i64
#[pyfunction]
fn nearest_leech_batch<'py>(
    py: Python<'py>,
    x: PyReadonlyArray2<'py, f64>,
) -> PyResult<Bound<'py, PyArray2<i64>>> {
    let shape = x.shape();
    let (b, d) = (shape[0], shape[1]);
    if d != LEECH_DIM {
        return Err(PyValueError::new_err(format!(
            "nearest_leech_batch expects [B, {LEECH_DIM}], got [{b}, {d}]"
        )));
    }
    // Materialise a contiguous owned copy so the GIL-released closure owns its
    // input (the borrow is tied to `py`).
    let input: Vec<f64> = x.as_array().iter().copied().collect();

    let out: Vec<i64> = py.allow_threads(move || {
        let mut out = vec![0i64; b * LEECH_DIM];
        out.par_chunks_mut(LEECH_DIM)
            .enumerate()
            .for_each(|(r, slot)| {
                let q = nearest_leech(row_to_array::<LEECH_DIM>(&input, r));
                slot.copy_from_slice(&q);
            });
        out
    });

    let arr = Array2::from_shape_vec((b, LEECH_DIM), out)
        .map_err(|e| PyValueError::new_err(e.to_string()))?;
    Ok(arr.into_pyarray(py))
}

/// nearest_e8_batch(x: ndarray[B,8] f64) -> ndarray[B,8] i64
#[pyfunction]
fn nearest_e8_batch<'py>(
    py: Python<'py>,
    x: PyReadonlyArray2<'py, f64>,
) -> PyResult<Bound<'py, PyArray2<i64>>> {
    let shape = x.shape();
    let (b, d) = (shape[0], shape[1]);
    if d != E8_DIM {
        return Err(PyValueError::new_err(format!(
            "nearest_e8_batch expects [B, {E8_DIM}], got [{b}, {d}]"
        )));
    }
    let input: Vec<f64> = x.as_array().iter().copied().collect();

    let out: Vec<i64> = py.allow_threads(move || {
        let mut out = vec![0i64; b * E8_DIM];
        out.par_chunks_mut(E8_DIM).enumerate().for_each(|(r, slot)| {
            let q = nearest_e8(row_to_array::<E8_DIM>(&input, r));
            slot.copy_from_slice(&q);
        });
        out
    });

    let arr =
        Array2::from_shape_vec((b, E8_DIM), out).map_err(|e| PyValueError::new_err(e.to_string()))?;
    Ok(arr.into_pyarray(py))
}

/// quant_error_batch_leech(x: ndarray[B,24] f64) -> ndarray[B] f64
/// Per-row squared error ||x - Q(x)||^2.
#[pyfunction]
fn quant_error_batch_leech<'py>(
    py: Python<'py>,
    x: PyReadonlyArray2<'py, f64>,
) -> PyResult<Bound<'py, PyArray1<f64>>> {
    let shape = x.shape();
    let (b, d) = (shape[0], shape[1]);
    if d != LEECH_DIM {
        return Err(PyValueError::new_err(format!(
            "quant_error_batch_leech expects [B, {LEECH_DIM}], got [{b}, {d}]"
        )));
    }
    let input: Vec<f64> = x.as_array().iter().copied().collect();

    let out: Vec<f64> = py.allow_threads(move || {
        (0..b)
            .into_par_iter()
            .map(|r| leech_quantization_error_sq(row_to_array::<LEECH_DIM>(&input, r)))
            .collect()
    });

    Ok(Array1::from_vec(out).into_pyarray(py))
}

/// quant_error_batch_e8(x: ndarray[B,8] f64) -> ndarray[B] f64
/// Per-row squared error ||x - Q(x)||^2.
#[pyfunction]
fn quant_error_batch_e8<'py>(
    py: Python<'py>,
    x: PyReadonlyArray2<'py, f64>,
) -> PyResult<Bound<'py, PyArray1<f64>>> {
    let shape = x.shape();
    let (b, d) = (shape[0], shape[1]);
    if d != E8_DIM {
        return Err(PyValueError::new_err(format!(
            "quant_error_batch_e8 expects [B, {E8_DIM}], got [{b}, {d}]"
        )));
    }
    let input: Vec<f64> = x.as_array().iter().copied().collect();

    let out: Vec<f64> = py.allow_threads(move || {
        (0..b)
            .into_par_iter()
            .map(|r| e8_error_sq(row_to_array::<E8_DIM>(&input, r)))
            .collect()
    });

    Ok(Array1::from_vec(out).into_pyarray(py))
}

#[pymodule]
fn lattice_vq(m: &Bound<'_, PyModule>) -> PyResult<()> {
    m.add("LEECH_DIM", LEECH_DIM)?;
    m.add("E8_DIM", E8_DIM)?;
    m.add_function(wrap_pyfunction!(nearest_leech_batch, m)?)?;
    m.add_function(wrap_pyfunction!(nearest_e8_batch, m)?)?;
    m.add_function(wrap_pyfunction!(quant_error_batch_leech, m)?)?;
    m.add_function(wrap_pyfunction!(quant_error_batch_e8, m)?)?;
    Ok(())
}
